# SPDX-FileCopyrightText: Copyright (c) 2023-2025 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
# SPDX-License-Identifier: Apache-2.0
#
# Licensed under the Apache License, Version 2.0 (the "License");
# you may not use this file except in compliance with the License.
# You may obtain a copy of the License at
#
#     http://www.apache.org/licenses/LICENSE-2.0
#
# Unless required by applicable law or agreed to in writing, software
# distributed under the License is distributed on an "AS IS" BASIS,
# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
# See the License for the specific language governing permissions and
# limitations under the License.
    # Only the resolve redirects should be force-cached despite HuggingFace's
    # "Cache-Control: no-store" (see proxy_ignore_headers below). This map lets
    # the huggingface.co location skip caching every other status: a no-store
    # 429 must never be written (it would overwrite a warm 302 and defeat the
    # proxy_cache_use_stale http_429 fallback), and dynamic 200 responses must
    # not be cached from this redirect-handling block. Evaluated after the
    # upstream response, so $upstream_status is set.
    map $upstream_status $hf_redirect_no_cache {
        default 1;
        302     0;
        307     0;
    }

    # HuggingFace main site - handles redirects (302/307)
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache-hf-redirects";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

        # Listen on 14128 for huggingface.co
        listen 14128 ssl;
        http2 off; # HF doesn't support HTTP/2
        server_name huggingface.co;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).
        proxy_cache proxy_ngc;

        # Cache redirects for shorter time with signed URLs
        proxy_cache_valid 302 307 45m;
        proxy_cache_valid 200 1h;
        proxy_cache_valid 429 0;  # Don't cache 429 responses - always retry upstream

        # CRITICAL: Serve stale content when upstream returns 429 (avoids client errors)
        proxy_cache_use_stale http_429;
        proxy_cache_background_update on;

        # Enable nginx retry for other errors (429 handled by stale serving)
        proxy_next_upstream         error timeout http_500 http_502 http_503 http_504;
        proxy_next_upstream_tries   4;
        proxy_next_upstream_timeout 60s;

        # Temporarily disable rate limiting to isolate 503 cause
        # limit_req  zone=hf_rps burst=10 nodelay;
        # limit_conn per_ip 8;

        set_by_lua_block $ssl_server_name {
          local headers = ngx.req.get_headers()
          return headers["Host"]
        }

        # CRITICAL: Don't cache any authentication tokens (causes 401 errors when expired)
        location ~ /.*token.* {
          proxy_cache off;
          proxy_pass_request_headers on;
          proxy_set_header Host $host;
          proxy_set_header User-Agent $http_user_agent;
          proxy_set_header X-Real-IP $remote_addr;
          proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
          proxy_set_header X-Forwarded-Proto $scheme;

          # Initialize upstream_last_modified to prevent warnings
          set $upstream_last_modified "";

          # Temporarily disable Lua access control to isolate 503 issue
          # access_by_lua_file /etc/nginx/conf.d/lua/lua-access.lua;

          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }

        location  / {
          proxy_pass_request_headers on;
          # Don't use Range header for redirects - not needed

          # Create SHA256 hash of authorization header for cache isolation
          set_by_lua_block $auth_hash {
            local auth_header = ngx.var.http_authorization or ""
            if auth_header == "" then
              return "noauth"
            end
            return ngx.encode_base64(ngx.sha1_bin(auth_header)):sub(1,16)  -- Use first 16 chars of SHA1 hash
          }

          proxy_cache_key $request_method|$uri|$arg_versionId|$arg_etag|$auth_hash;

          # HuggingFace returns "Cache-Control: no-store" and "Vary: Origin, Accept"
          # on the resolve 302 redirects. Without this, nginx honors no-store and
          # never caches them, so every chunk re-resolves upstream and HF rate-limits
          # (429). The redirect Location is a presigned URL valid ~1h, and the
          # proxy_cache_valid 302 TTL above (45m) keeps cached redirects within that
          # validity window. Auth is already isolated via $auth_hash in the cache key.
          proxy_ignore_headers Cache-Control Expires Set-Cookie Vary;

          # proxy_ignore_headers is status-blind, so restrict what gets written:
          # only 302/307 redirects are cached here. This keeps no-store 429s (and
          # any dynamic 200) out of the cache so they cannot overwrite a warm 302.
          proxy_no_cache $hf_redirect_no_cache;

          # Initialize upstream_last_modified to prevent warnings
          set $upstream_last_modified "";

          # Don't forward Range header to huggingface.co - redirects don't need it
          proxy_set_header Range "";

          # Temporarily disable Lua access control to isolate 503 issue
          # access_by_lua_file /etc/nginx/conf.d/lua/lua-access.lua;

          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

    # HuggingFace Xet CAS server - content-addressable storage backend
    # (cas-server.xethub.hf.co only).
    #
    # The Xet reconstruction protocol streams chunk data from per-request
    # presigned S3 URLs and is not cacheable through this proxy. Routing it
    # through the generic *.hf.co content cache below forced range rewrites
    # and cache locking that broke upstream SSL handshakes. An exact
    # server_name takes priority over the *.hf.co regex, so only this host
    # bypasses the cache and proxies straight through to the upstream; other
    # *.xethub.hf.co hosts keep falling through to the content cache.
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache-hf-xet-bypass";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

        # Listen on 14128 for the Xet CAS host
        listen 14128 ssl;
        http2 off; # HF doesn't support HTTP/2
        server_name cas-server.xethub.hf.co;

        set_by_lua_block $ssl_server_name {
          local headers = ngx.req.get_headers()
          return headers["Host"]
        }

        location / {
          # Bypass the cache entirely: pass the request through unchanged.
          proxy_cache off;
          # Server-level `proxy_force_ranges on` (from proxy-common.conf)
          # would still ask nginx to buffer the full streaming response to
          # slice a Range, which is the failure mode this server block
          # exists to avoid. Turn it off explicitly so the bypass is complete.
          proxy_force_ranges off;
          # The CAS endpoint only negotiates TLS 1.2; proxy-common.conf pins
          # proxy_ssl_protocols to TLSv1.3, so the upstream handshake always
          # failed ("upstream temporarily disabled while SSL handshaking")
          # and every peer returned 502. Allow TLS 1.2 here so the handshake
          # succeeds. Scoped to this host only; other upstreams keep 1.3.
          proxy_ssl_protocols TLSv1.2 TLSv1.3;
          proxy_pass_request_headers on;

          # Forward the client Range untouched so chunk reads work as-is.
          proxy_set_header Range $http_range;

          # Initialize upstream_last_modified to prevent warnings
          set $upstream_last_modified "";

          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

    # HuggingFace CDN/Bridge - handles actual file content with range support
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache-hf-content";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

        # Listen on 14128 for CDN endpoints
        listen 14128 ssl;
        http2 off; # HF CDN doesn't support HTTP/2
        # Cache HF CDN hosts (match any *.hf.co).
        server_name ~^(.+\.)?hf\.co$;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).
        proxy_cache proxy_ngc;

        # Cache file content for longer periods
        # HF CDN file content is immutable model data; validity driven by
        # cache.valid. Redirect (302) validity above stays short because it is
        # tied to presigned URL lifetime.
        proxy_cache_valid 200 206 31d;
        proxy_cache_valid 302 307 45m;  # Short cache for any redirects from CDN
        proxy_cache_valid 429 0;  # Don't cache 429 responses - always retry upstream

        # CRITICAL: Serve stale content when upstream returns 429 (avoids client errors)
        proxy_cache_use_stale http_429;
        proxy_cache_background_update on;

        # Enable nginx retry for other errors (429 handled by stale serving)
        proxy_next_upstream         error timeout http_500 http_502 http_503 http_504;
        proxy_next_upstream_tries   4;
        proxy_next_upstream_timeout 60s;

        # No rate limiting for file content downloads - these are cached file serves
        # Rate limiting is handled at the redirect level (huggingface.co)

        set_by_lua_block $ssl_server_name {
          local headers = ngx.req.get_headers()
          return headers["Host"]
        }

        location  / {
          proxy_pass_request_headers on;
          # Use Range header for file content - enables partial downloads
          proxy_set_header Range $http_range;
          proxy_cache_key $request_method|$uri|$arg_versionId|$http_range;

          # HF-OPTIMIZED: Buffers sized for 10MB median object size
          # Buffer profile inherited from proxy-common.conf (aligned fleet-wide).

          # Initialize upstream_last_modified to prevent warnings
          set $upstream_last_modified "";

          # Temporarily disable Lua access control to isolate 503 issue
          # access_by_lua_file /etc/nginx/conf.d/lua/lua-access.lua;

          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

