    # The caching layer
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

        # Listen on 14128, for all hostnames.
        listen 14128 ssl;
        # override specific configurations from proxy-common.conf
        http2 off;
        server_name ~^x?l?files\.(stg\.)?ngc\.nvidia\.com$;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).
        proxy_cache proxy_ngc;

        # Buffer profile inherited from proxy-common.conf (aligned fleet-wide).

        # Reliability for NGC downloads  
        # NGC model blobs are content-addressed and immutable; validity is
        # driven by cache.valid so expiry does not force refetching.
        proxy_cache_valid 200 206 31d;
        proxy_cache_valid 429 0;
        proxy_cache_use_stale http_429 error timeout updating;
        proxy_cache_background_update on;
        proxy_next_upstream error timeout http_500 http_502 http_503 http_504;

        # NGC CDN connection optimizations
        proxy_connect_timeout 10s;      # Allow time for CDN connection setup
        proxy_set_header Connection "";  # Enable keep-alive to upstream

        set_by_lua_block $ssl_server_name {
          local headers = ngx.req.get_headers()
          return headers["Host"]
        }

        location  / {
          # Initialize upstream_last_modified to prevent warnings
          set $upstream_last_modified "";

          # Override common 15s - 16MB chunks from NGC CDN can spike
          proxy_read_timeout 30s;

          proxy_pass_request_headers on;
          proxy_set_header Range $http_range;
          proxy_cache_key $request_method|$uri|$arg_versionId|$http_range;
          access_by_lua_file /etc/nginx/conf.d/lua/lua-access.lua;
          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

