# SPDX-FileCopyrightText: Copyright (c) 2023-2025 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
# SPDX-License-Identifier: Apache-2.0
#
# Licensed under the Apache License, Version 2.0 (the "License");
# you may not use this file except in compliance with the License.
# You may obtain a copy of the License at
#
#     http://www.apache.org/licenses/LICENSE-2.0
#
# Unless required by applicable law or agreed to in writing, software
# distributed under the License is distributed on an "AS IS" BASIS,
# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
# See the License for the specific language governing permissions and
# limitations under the License.
    # The caching layer
    server {
        # For access logs
        set $docker_proxy_request_type "nvcf-proxy-cache-s3";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout s3_log buffer=256k flush=10s;

        # OV Application relies on If-Match header to guaranty client receives the content it requested.
        # They add If-Match header as part of S3 signature. Nginx will drop If-Match header and won't forward
        # it to S3. We need to forward this header to S3 for Signature verification to work. The block of code
        # below is a WAR for the If-Match requirement.

        set_by_lua_block $filtered_args {
          local args = ngx.req.get_uri_args()
          local filtered = {}
          local strip = {
              ["versionId"] = true,
              ["X-Amz-Algorithm"] = true,
              ["X-Amz-Credential"] = true,
              ["X-Amz-Date"] = true,
              ["X-Amz-Expires"] = true,
              ["X-Amz-Signature"] = true,
              ["X-Amz-Security-Token"] = true,
              ["X-Amz-SignedHeaders"] = true,
          }
          for k, v in pairs(args) do
            if not strip[k] then
              filtered[k] = v
            end
          end
          return ngx.encode_args(filtered)
        }

        # Listen on 14128, for all hostnames.
        listen 14128 ssl;
        http2 off;
        server_name ~^(?<bucket_name>[^\.]+)(\.s3(\.(?<bucket_region>[^\.]+))?)?\.amazonaws\.com$;
        proxy_cache proxy_s3;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).

        # S3-optimized cache settings
        proxy_cache_valid 200 206 31d;
        proxy_cache_valid 404 1h;  # Cache 404 responses for 1 hour to reduce S3 requests
        proxy_cache_use_stale error timeout invalid_header updating http_500 http_502 http_503 http_504;

        # Sized for the large S3 range reads seen in practice (~60-70MB .usdz chunks)
        # Buffer profile inherited from proxy-common.conf (aligned fleet-wide).
        set_by_lua_block $retry_after {
            return 15
        }

        slice 0;

        set_by_lua_block $request_range {
            local headers, err = ngx.req.get_headers()
            if ngx.var.request_method == "HEAD" then
                return ngx.var.http_range
            end
            if headers["Range"] ~= nil then
                return ngx.var.http_range
            end
            return ngx.var.slice_range
        }

        set_by_lua_block $bypass_cache {
            local uri = ngx.var.request_uri

            -- Bucket-level API: /?acl, /?cors, /?list-type=2, etc.
            if string.find(uri, "^/%?") then
                return "1"
            end

            -- Allowlist: bypass if any query param is not one we explicitly recognise
            -- as safe to ignore/strip. Future S3 API params automatically bypass.
            local safe = {
                ["versionId"] = true,
                ["X-Amz-Algorithm"] = true,
                ["X-Amz-Credential"] = true,
                ["X-Amz-Date"] = true,
                ["X-Amz-Expires"] = true,
                ["X-Amz-Signature"] = true,
                ["X-Amz-Security-Token"] = true,
                ["X-Amz-SignedHeaders"] = true,
                ["response-content-type"] = true,
                ["response-content-disposition"] = true,
                ["response-content-encoding"] = true,
                ["response-expires"] = true,
                ["response-cache-control"] = true,
                ["response-content-language"] = true,
            }
            for k, _ in pairs(ngx.req.get_uri_args()) do
                if not safe[k] then
                    return "1"
                end
            end

            return "0"
        }

        location  / {

          proxy_set_header Range $request_range;
          set $upstream_last_modified "";
          proxy_pass_request_headers on;

          # Configures cache bypass based on the Cache-Control header.
          set $disable_cache $bypass_cache;

          if ($http_cache_control ~* "no-cache") {
            set $disable_cache "1";
          }

          proxy_cache_bypass $disable_cache;
          proxy_no_cache $disable_cache;
          proxy_set_header If-Match $http_if_match;

          proxy_cache_key $bucket_region|$bucket_name|$request_method|$uri|$arg_versionId|$http_if_match|$filtered_args|$request_range;
          access_by_lua_file /etc/nginx/conf.d/lua/lua-access.lua;
          proxy_set_header Host $host;
          proxy_pass $scheme://$host;

          header_filter_by_lua_block {
              if ngx.var.request_method ~= "GET" and ngx.var.request_method ~= "HEAD" then
                return
              end
              local headers, err = ngx.resp.get_headers()
              if ngx.status == 200 and ngx.var.request_method == "HEAD" and headers["content-length"] == nil and ngx.var.request_uri ~= '/' then
                -- This change should be reomved when OMPE-36810 is fixed.
                ngx.shared.head_request_cache:delete(ngx.var.request_uri)
                ngx.log(ngx.ERR, "Bad state. Content-Length missing in HEAD response.")
                ngx.status = 429
                ngx.header.content_length = 0
                ngx.header.retry_after = ngx.var.retry_after
                ngx.exit(ngx.status)
                return
              end

              local cache_status = (ngx.var.upstream_cache_status or "")
              if cache_status ~= "HIT" then
                return
              end
              local http_cache = require("http_cache")
              local cache_metadata = http_cache.get_metadata()
              if cache_metadata and ngx.var.upstream_last_modified and ngx.var.upstream_last_modified ~= "" then
                if cache_metadata.last_modified < ngx.parse_http_time(ngx.var.upstream_last_modified) then
                    http_cache.purge()
                    ngx.log(ngx.ERR,
                        "Purged stale cache entry. Cached Last-Modified: ",
                        ngx.http_time(cache_metadata.last_modified),
                        ", Upstream Last-Modified: ",
                        ngx.var.upstream_last_modified)

                        ngx.status = 429
                        ngx.header.content_length = 0
                        ngx.exit(ngx.status)
                end
              end
          }
        }
    }


    server {
        # For access logs
        listen 14128 ssl default_server reuseport;
        set $docker_proxy_request_type "nvcf-proxy-cache-default";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout nucleus_log buffer=256k flush=10s;

        proxy_cache_valid 200 206 31d;
        proxy_cache_use_stale error timeout invalid_header updating http_500 http_502 http_503 http_504;
        # Buffer profile inherited from proxy-common.conf (aligned fleet-wide).

        location / {
          proxy_cache_bypass 1;
          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

