# SPDX-FileCopyrightText: Copyright (c) 2023-2025 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
# SPDX-License-Identifier: Apache-2.0
#
# Licensed under the Apache License, Version 2.0 (the "License");
# you may not use this file except in compliance with the License.
# You may obtain a copy of the License at
#
#     http://www.apache.org/licenses/LICENSE-2.0
#
# Unless required by applicable law or agreed to in writing, software
# distributed under the License is distributed on an "AS IS" BASIS,
# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
# See the License for the specific language governing permissions and
# limitations under the License.
    # The caching layer

    # Add to include callers

        set $disable_cache "0";

        log_by_lua_block {
            local cache_status = ngx.var.upstream_cache_status
            local request_uri = ngx.var.request_uri
            local body_size = tonumber(ngx.var.body_bytes_sent)
            local remote_addr = ngx.var.remote_addr
            local request_time = tonumber(ngx.var.request_time)
            local http_status = ngx.var.status
            local request_method = ngx.var.request_method
            -- $upstream_response_time becomes a comma/colon-separated list when
            -- nginx retries upstreams (proxy_next_upstream), e.g. after a failed
            -- upstream SSL handshake. tonumber() on that string returns nil, so
            -- coerce here and guard every arithmetic use below against nil.
            local upstream_time = tonumber(ngx.var.upstream_response_time)
            local host = ngx.var.host

            if request_uri ~= nil and cache_status ~= nil and remote_addr ~= nil and not string.find(request_uri, "manifest") then
                if request_time ~= nil and request_time > 0 then
                    proxy_http_request_time_ms_total:inc(request_time, {request_method, cache_status, http_status})
                    proxy_http_requests_count:inc(1, {request_method, cache_status, http_status})

                    metric_latency:observe(request_time, {host, request_method, cache_status, http_status})
                    if body_size ~= nil then
                        proxy_cache_throughput:observe(body_size / request_time, {cache_status, http_status})
                        if upstream_time ~= nil and upstream_time > 0 then
                          proxy_cache_upstream_throughput:observe(body_size / upstream_time, {host, http_status})
                          metric_upstream_latency:observe(upstream_time, {host, request_method, cache_status, http_status})
                          proxy_http_upstream_requests_count:inc(1, {request_method, cache_status, http_status})
                        end
                    end
                end

                if body_size ~= nil then
                    proxy_response_body_size:set(body_size, {cache_status, http_status})
                    metric_response_sizes:observe(body_size)
                end
            end
        }

        set_by_lua_block $cache_ttl {
          return 30
        }

        ssl_verify_client optional;
        proxy_ssl_protocols TLSv1.3;
        ssl_protocols TLSv1.3;
        ssl_certificate /etc/certs/ssl-bundle.crt;
        ssl_certificate_key /etc/certs/leaf-ca.key;
        ssl_client_certificate /etc/ssl/certs/ca-certificates.crt;
        lua_ssl_trusted_certificate /etc/ssl/certs/ca-certificates.crt;
        ssl_certificate_by_lua_file /etc/nginx/conf.d/lua/lua-ssl.lua;

        # Copied from GFN proxy-cache
        sendfile on;
        tcp_nopush on;
        tcp_nodelay on;
        aio threads;
        reset_timedout_connection on;
        server_tokens off; # Don't reveal OpenResty version to clients.
        proxy_request_buffering off; # don't buffer PUT's
        client_max_body_size 0;


        # Timeout Configuration - Optimized for shared cluster
        keepalive_timeout  300s;
        keepalive_requests 1000;  # Conservative connection reuse for shared environment
        send_timeout 60s;
        client_body_timeout 60s;
        client_header_timeout 60s;

        proxy_read_timeout 15s;
        proxy_send_timeout 60s;

        # Configure cache size and Path
        proxy_http_version 1.1;
        proxy_cache_convert_head off;
        proxy_cache_methods GET HEAD;
        proxy_ssl_server_name on;
        proxy_buffering on;

        # Canonical buffer profile for every cache server block that includes this file.
        # Sized for the large objects these blocks actually serve (multi-GB NGC blobs,
        # ~60-70MB S3 range reads, ~67MB HF chunks): 16MB in memory before spilling, 1m
        # disk writes, 2048m ceiling on the per-response temp/cache file. A directive can
        # appear once per context, so do not also set these in a block; override the whole
        # set in a block only if it genuinely needs a different profile.
        proxy_buffer_size 128k;
        proxy_buffers 64 256k;
        proxy_busy_buffers_size 2m;
        proxy_temp_file_write_size 1m;
        proxy_max_temp_file_size 2048m;

        # Upstream connection optimization
        proxy_set_header Connection "";  # Enable keepalive to upstreams
        # proxy_cache_valid and proxy_cache_use_stale moved to individual configs for optimization
        proxy_cache_bypass $cookie_nocache $arg_nocache $http_pragma;
        proxy_cache_revalidate on;
        add_header X-Cache-Status $upstream_cache_status;

            # DNS resolver with aggressive caching for CDN services (very stable IPs)
            resolver local=on ipv6=off valid=300s;   # 5min DNS cache - faster recovery from bad S3 nodes

        chunked_transfer_encoding on;

        # Use cache locking
        # This forces additional requests to wait to be served through the cache
        # until the first request for the same resource is completed, helping cut bandwidth costs.
        proxy_cache_lock on;
        # Canonical lock timeouts for every cache server block that includes this file.
        # Sized for the slowest expected upstream fetch (multi-GB blobs at worst-case
        # rates). These are ceilings that only take effect when a fetch is slow, so they
        # are safe for small objects too. Do not override per block; keep aligned.
        # lock_timeout covers p99 of observed 10GB fills (2026-07-06 logs: p50 707s,
        # p90 1142s, max ~1200s); a waiter that gives up mid-fill re-downloads from
        # origin, so this must outlast the slow tail, not the average.
        proxy_cache_lock_timeout 1200s;
        proxy_cache_lock_age 3600s;

        # Some extra settings to maximize cache hits and efficiency
        proxy_force_ranges on;
        proxy_ignore_client_abort on;

        # Verify SSL certs, and use the system CA bundle.
        proxy_ssl_verify on;
        proxy_ssl_trusted_certificate /etc/ssl/certs/ca-certificates.crt;
