    # Only the resolve redirects should be force-cached despite HuggingFace's
    # "Cache-Control: no-store" (see proxy_ignore_headers below). This map lets
    # the huggingface.co location skip caching every other status: a no-store
    # 429 must never be written (it would overwrite a warm 302 and defeat the
    # proxy_cache_use_stale http_429 fallback), and dynamic 200 responses must
    # not be cached from this redirect-handling block. Evaluated after the
    # upstream response, so $upstream_status is set.
    map $upstream_status $hf_redirect_no_cache {
        default 1;
        302     0;
        307     0;
    }

    # HuggingFace main site - handles redirects (302/307)
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache-hf-redirects";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

        # Listen on 14128 for huggingface.co
        listen 14128 ssl;
        http2 off; # HF doesn't support HTTP/2
        server_name huggingface.co;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).
        proxy_cache proxy_ngc;

        # Cache redirects for shorter time with signed URLs
        proxy_cache_valid 302 307 45m;
        proxy_cache_valid 200 1h;
        proxy_cache_valid 429 0;  # Don't cache 429 responses - always retry upstream

        # CRITICAL: Serve stale content when upstream returns 429 (avoids client errors)
        proxy_cache_use_stale http_429;
        proxy_cache_background_update on;

        # Enable nginx retry for other errors (429 handled by stale serving)
        proxy_next_upstream         error timeout http_500 http_502 http_503 http_504;
        proxy_next_upstream_tries   4;
        proxy_next_upstream_timeout 60s;

        # Temporarily disable rate limiting to isolate 503 cause
        # limit_req  zone=hf_rps burst=10 nodelay;
        # limit_conn per_ip 8;

        set_by_lua_block $ssl_server_name {
          local headers = ngx.req.get_headers()
          return headers["Host"]
        }

        # CRITICAL: Don't cache any authentication tokens (causes 401 errors when expired)
        location ~ /.*token.* {
          proxy_cache off;
          proxy_pass_request_headers on;
          proxy_set_header Host $host;
