          set $upstream_last_modified "";

          proxy_set_header Host $host;
          proxy_pass $scheme://$host;
        }
    }

    # HuggingFace CDN/Bridge - handles actual file content with range support
    server {
        set $docker_proxy_request_type "nvcf-proxy-cache-hf-content";
        include  /etc/nginx/conf.d/sites/proxy-common.conf;
        access_log /dev/stdout main buffer=256k flush=10s;

