        listen 14128 ssl;
        http2 off; # HF CDN doesn't support HTTP/2
        # Cache HF CDN hosts (match any *.hf.co).
        server_name ~^(.+\.)?hf\.co$;
        # Cache-lock timeouts inherited from proxy-common.conf (aligned fleet-wide).
        proxy_cache proxy_ngc;

